To make this final dictionnary, we’re going to input the shade tolerance, drought tolerance and waterlogging tolerance of each of our tree species in a dictionnary, with exactly the same mentions as the markdown tables above (e.g. “Shade intolerant”, “Somewhat shade intolerant”, etc.).

Normally, this is quite easy to do using the values from 

Niinemets and Valladares (2006).

from functionsForCalibration import *
import json
import math

with open('./SpeciesParametersSets/speciesNamesDictionnary.json', 'r') as file: speciesDict = json.load(file)

with open('./ReferencesAndData/Functional Traits/SpeciesTolerancesAndTargets.json', 'r') as file: SpeciesTolerancesAndTargets = json.load(file)

dictOfShadeTolerance ={}
dictOfDroughtTolerance = {}
dictOfWaterloggingTolerance = {}
dictOfConiferousVersusAngiosperm = {}
dictOfEvergreenVersusDeciduous = {}

shade_labels = {
    1: "Shade intolerant",
    2: "Somewhat shade intolerant",
    3: "Intermediate shade tolerant",
    4: "Somewhat shade tolerant",
    5: "Shade tolerant",
}

drought_labels = {
    1: "Drought intolerant",
    2: "Somewhat drought intolerant",
    3: "Intermediate drought tolerant",
    4: "Somewhat drought tolerant",
    5: "Drought tolerant",
}

waterlogging_labels = {
    1: "Waterlogging intolerant",
    2: "Somewhat waterlogging intolerant",
    3: "Intermediate waterlogging tolerant",
    4: "Somewhat waterlogging tolerant",
    5: "Waterlogging tolerant",
}

for speciesCode in speciesDict:
    # Computing tolerance labels
    dictOfShadeTolerance[speciesCode] = shade_labels[int(math.floor(SpeciesTolerancesAndTargets[speciesCode]['Shade'] + 0.5))]
    dictOfDroughtTolerance[speciesCode] = drought_labels[int(math.floor(SpeciesTolerancesAndTargets[speciesCode]['Drought'] + 0.5))]
    dictOfWaterloggingTolerance[speciesCode] = waterlogging_labels[int(math.floor(SpeciesTolerancesAndTargets[speciesCode]['Waterlogging'] + 0.5))]
    if SpeciesTolerancesAndTargets[speciesCode]['Gymnosperm'] == "Y":
        dictOfConiferousVersusAngiosperm[speciesCode] = "Coniferous"
    else:
        dictOfConiferousVersusAngiosperm[speciesCode] = "Angiosperm"
    if SpeciesTolerancesAndTargets[speciesCode]['Evergreen'] == "Y":
        dictOfEvergreenVersusDeciduous[speciesCode] = "Evergreen"
    else:
        dictOfEvergreenVersusDeciduous[speciesCode] = "Deciduous"

finalDictionaryWithBounds = {}
for species in dictOfShadeTolerance.keys():
    finalDictionaryWithBounds[species] = dict()
    for parameter in bounds_shadeTolerance_Parameters:
        finalDictionaryWithBounds[species][parameter] = dict()
        finalDictionaryWithBounds[species][parameter]["lower"] = bounds_shadeTolerance_Parameters[parameter][dictOfShadeTolerance[species]]["lower"]
        finalDictionaryWithBounds[species][parameter]["upper"] = bounds_shadeTolerance_Parameters[parameter][dictOfShadeTolerance[species]]["upper"]
    for parameter in bounds_droughtTolerance_Parameters:
        finalDictionaryWithBounds[species][parameter] = dict()
        finalDictionaryWithBounds[species][parameter]["lower"] = bounds_droughtTolerance_Parameters[parameter][dictOfDroughtTolerance[species]]["lower"]
        finalDictionaryWithBounds[species][parameter]["upper"] = bounds_droughtTolerance_Parameters[parameter][dictOfDroughtTolerance[species]]["upper"]
    for parameter in bounds_waterloggingTolerance_Parameters:
        finalDictionaryWithBounds[species][parameter] = dict()
        finalDictionaryWithBounds[species][parameter]["lower"] = bounds_waterloggingTolerance_Parameters[parameter][dictOfWaterloggingTolerance[species]]["lower"]
        finalDictionaryWithBounds[species][parameter]["upper"] = bounds_waterloggingTolerance_Parameters[parameter][dictOfWaterloggingTolerance[species]]["upper"]
    for parameter in bounds_coniferousVersusAngiosperms_Parameters:
        finalDictionaryWithBounds[species][parameter] = dict()
        finalDictionaryWithBounds[species][parameter]["lower"] = bounds_coniferousVersusAngiosperms_Parameters[parameter][dictOfConiferousVersusAngiosperm[species]]["lower"]
        finalDictionaryWithBounds[species][parameter]["upper"] = bounds_coniferousVersusAngiosperms_Parameters[parameter][dictOfConiferousVersusAngiosperm[species]]["upper"]
    for parameter in bounds_evergreenVersusDeciduous_Parameters:
        finalDictionaryWithBounds[species][parameter] = dict()
        finalDictionaryWithBounds[species][parameter]["lower"] = bounds_evergreenVersusDeciduous_Parameters[parameter][dictOfEvergreenVersusDeciduous[species]]["lower"]
        finalDictionaryWithBounds[species][parameter]["upper"] = bounds_evergreenVersusDeciduous_Parameters[parameter][dictOfEvergreenVersusDeciduous[species]]["upper"]

print(finalDictionaryWithBounds)

# We save the dictionnary into a JSON file
import json
with open('./SpeciesParametersSets/SpeciesParameterBounds.json', 'w') as f:
    json.dump(finalDictionaryWithBounds, f)
